```python

# 提取研报中的历史预测数据
historical_forecasts = [
    {
        "eps": 0.17,
        "net_profit": 19.6,
        "estimated_pe": null,
        "year": 2022
    },
    {
        "eps": 0.10,
        "net_profit": 10.9,
        "estimated_pe": null,
        "year": 2023
    },
    {
        "eps": 0.17,
        "net_profit": 19.8,
        "estimated_pe": null,
        "year": 2024
    }
]

# 提取最新预测年份和数据
latest_forecast = max(historical_forecasts, key=lambda x: x["year"])
target_year = latest_forecast["year"]
target_net_profit = latest_forecast["net_profit"]
target_eps = latest_forecast["eps"]

# 计算PE
# 假设研报中给出了目标市值和股价，用于计算PE
# 这里假设目标市值为690亿元，股价为6.1元/股
# 实际应用中需要从研报中准确提取这些数据
total_shares = 690 / 6.1
calculated_pe = total_shares / target_eps

# 构建输出JSON
output_json = {
    "forecasts": [
        {
            "year": target_year,
            "net_profit": target_net_profit,
            "eps": target_eps,
            "pe": calculated_pe
        }
    ]
}

print(output_json)
